const input = $input.first().json;

const required = ['symbol', 'exchange', 'strategy_name', 'timeframe'];
for (const key of required) {
  if (!String(input[key] || '').trim()) {
    throw new Error(`Missing required field: ${key}`);
  }
}

if (input.risk_percent_per_trade <= 0 || input.risk_percent_per_trade > 5) {
  throw new Error('risk_percent_per_trade must be between 0 and 5 for production safety.');
}

if (input.stop_loss_percent <= 0 || input.stop_loss_percent > 10) {
  throw new Error('stop_loss_percent must be between 0 and 10.');
}

if (input.min_signal_confidence < 50 || input.min_signal_confidence > 95) {
  throw new Error('min_signal_confidence must be between 50 and 95.');
}

if (!input.dry_run && !String(input.broker_execution_webhook_url || '').trim()) {
  throw new Error('Missing broker_execution_webhook_url while dry_run is false.');
}

return [{
  json: {
    ...input,
    run_id: `run_${Date.now()}_${Math.random().toString(16).slice(2, 8)}`,
    triggered_at: new Date().toISOString()
  }
}];

const cfg = $input.first().json;

const cleanKey = (key) => String(key || '').trim().replace(/^Bearer\s+/i, '');
let apiKey = cleanKey(cfg.market_data_api_key);

if (!apiKey) {
  try {
    const cred = await this.getCredentials('httpHeaderAuth');
    apiKey = cleanKey(cred.value || cred.headerValue);
  } catch (e) {
    // credential not configured on this node
  }
}

const symbol = cfg.symbol;
let price = 0;
let open = 0;
let high = 0;
let low = 0;
let prevClose = 0;
let changePercent = 0;
let vendor = '';
const sourceErrors = [];

if (apiKey) {
  try {
    const quote = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.alphavantage.co/query',
      qs: {
        function: 'GLOBAL_QUOTE',
        symbol,
        apikey: apiKey
      },
      json: true,
      timeout: 30000
    });

    const q = quote['Global Quote'] || {};
    price = Number(q['05. price'] || 0);
    open = Number(q['02. open'] || 0);
    high = Number(q['03. high'] || 0);
    low = Number(q['04. low'] || 0);
    prevClose = Number(q['08. previous close'] || 0);
    changePercent = Number(String(q['10. change percent'] || '0').replace('%', ''));
    vendor = 'alpha_vantage';
  } catch (err) {
    sourceErrors.push(`alpha_vantage: ${err?.message || 'request_failed'}`);
  }
}

if (!price || Number.isNaN(price)) {
  try {
    const yahoo = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://query1.finance.yahoo.com/v7/finance/quote',
      qs: {
        symbols: symbol
      },
      json: true,
      timeout: 30000
    });

    const r = yahoo?.quoteResponse?.result?.[0] || {};
    price = Number(r.regularMarketPrice || 0);
    open = Number(r.regularMarketOpen || 0);
    high = Number(r.regularMarketDayHigh || 0);
    low = Number(r.regularMarketDayLow || 0);
    prevClose = Number(r.regularMarketPreviousClose || 0);
    changePercent = Number(r.regularMarketChangePercent || 0);
    vendor = 'yahoo_finance';
  } catch (err) {
    sourceErrors.push(`yahoo_finance: ${err?.message || 'request_failed'}`);
  }
}

if (!price || Number.isNaN(price)) {
  try {
    const stooqSymbol = `${symbol}.US`;
    const csv = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://stooq.com/q/l/',
      qs: {
        s: stooqSymbol,
        f: 'sd2t2ohlcv',
        h: 0,
        e: 'csv'
      },
      json: false,
      timeout: 30000
    });

    const text = String(csv || '').trim();
    const lines = text.split('\n').map((x) => x.trim()).filter(Boolean);
    if (lines.length < 2) {
      throw new Error('empty_csv');
    }

    const header = lines[0].split(',').map((h) => h.trim().toLowerCase());
    const cols = lines[1].split(',').map((c) => c.trim());
    const getByName = (name) => {
      const idx = header.indexOf(name);
      return idx >= 0 ? cols[idx] : '';
    };

    const closeStr = getByName('close');
    const openStr = getByName('open');
    const highStr = getByName('high');
    const lowStr = getByName('low');

    price = Number(closeStr || 0);
    open = Number(openStr || 0);
    high = Number(highStr || 0);
    low = Number(lowStr || 0);
    prevClose = Number(getByName('prev close') || 0);

    if (!price || Number.isNaN(price)) {
      throw new Error(`invalid_close_value:${closeStr}`);
    }

    changePercent = prevClose > 0 ? Number((((price - prevClose) / prevClose) * 100).toFixed(4)) : 0;
    vendor = 'stooq';
  } catch (err) {
    sourceErrors.push(`stooq: ${err?.message || 'request_failed'}`);
  }
}

if (!price || Number.isNaN(price)) {
  throw new Error(`Unable to fetch market data for ${symbol}. Sources failed: ${sourceErrors.join(' | ') || 'no providers available'}`);
}

return [{
  json: {
    ...cfg,
    market_data: {
      symbol,
      price,
      open,
      high,
      low,
      previous_close: prevClose,
      change_percent: changePercent,
      collected_at: new Date().toISOString(),
      vendor,
      source_fallback_used: vendor !== 'alpha_vantage',
      source_errors: sourceErrors
    }
  }
}];

const payload = $input.first().json;

const cleanKey = (key) => String(key || '').trim().replace(/^Bearer\s+/i, '');
let apiKey = cleanKey(payload.openrouter_api_key);

if (!apiKey) {
  try {
    const cred = await this.getCredentials('httpHeaderAuth');
    apiKey = cleanKey(cred.value || cred.headerValue);
  } catch (e) {
    // credential not configured on this node
  }
}

if (!apiKey) {
  throw new Error('Missing openrouter_api_key. Add in payload or attach HTTP Header Auth credential to this node.');
}

const model = payload.openrouter_model || 'openai/gpt-4o-mini';
const md = payload.market_data;

const systemPrompt = 'You are a disciplined quant trading assistant. Return only strict JSON with keys: signal, confidence, rationale, key_levels, invalidation, risk_notes. signal must be BUY, SELL, or HOLD.';
const userPrompt = `Analyze ${payload.symbol} on ${payload.timeframe}.\nPrice: ${md.price}\nOpen: ${md.open}\nHigh: ${md.high}\nLow: ${md.low}\nPrevious Close: ${md.previous_close}\nChange %: ${md.change_percent}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://openrouter.ai/api/v1/chat/completions',
  headers: {
    Authorization: `Bearer ${apiKey}`,
    'Content-Type': 'application/json',
    'X-Title': 'Stock Market Agent'
  },
  body: {
    model,
    temperature: 0.2,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]
  },
  json: true,
  timeout: 60000
});

const raw = response.choices?.[0]?.message?.content;
if (!raw) {
  throw new Error('AI Analysis Agent returned empty content.');
}

let analysis;
try {
  analysis = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch {
  throw new Error('Failed to parse AI analysis JSON.');
}

return [{
  json: {
    ...payload,
    ai_analysis: {
      ...analysis,
      model: response.model || model,
      usage: response.usage || null,
      analyzed_at: new Date().toISOString()
    }
  }
}];

const item = $input.first().json;
const analysis = item.ai_analysis || {};

const validSignals = ['BUY', 'SELL', 'HOLD'];
const signal = String(analysis.signal || 'HOLD').toUpperCase();
const confidence = Number(analysis.confidence || 0);

if (!validSignals.includes(signal)) {
  throw new Error(`Invalid signal from AI analysis: ${analysis.signal}`);
}

const passes = confidence >= Number(item.min_signal_confidence || 70);

return [{
  json: {
    ...item,
    validated_signal: {
      signal,
      confidence,
      passed: passes,
      reason: passes
        ? 'Signal confidence meets threshold.'
        : `Signal confidence ${confidence} is below threshold ${item.min_signal_confidence}.`,
      validated_at: new Date().toISOString()
    }
  }
}];

const item = $input.first().json;
const md = item.market_data;
const signal = item.validated_signal;

const price = Number(md.price);
const equity = Number(item.account_equity);
const riskPct = Number(item.risk_percent_per_trade) / 100;
const stopPct = Number(item.stop_loss_percent) / 100;
const maxPosPct = Number(item.max_position_size_percent) / 100;

const riskCapital = equity * riskPct;
const stopDistance = price * stopPct;
const rawQty = stopDistance > 0 ? Math.floor(riskCapital / stopDistance) : 0;
const maxNotional = equity * maxPosPct;
const cappedQty = Math.max(0, Math.min(rawQty, Math.floor(maxNotional / price)));

const takeProfitPrice = price * (1 + Number(item.take_profit_percent) / 100);
const stopLossPrice = signal.signal === 'SELL'
  ? price * (1 + Number(item.stop_loss_percent) / 100)
  : price * (1 - Number(item.stop_loss_percent) / 100);

return [{
  json: {
    ...item,
    risk_plan: {
      risk_capital: Number(riskCapital.toFixed(2)),
      quantity: cappedQty,
      stop_loss_price: Number(stopLossPrice.toFixed(4)),
      take_profit_price: Number(takeProfitPrice.toFixed(4)),
      max_notional: Number(maxNotional.toFixed(2)),
      estimated_notional: Number((cappedQty * price).toFixed(2)),
      valid: cappedQty > 0,
      assessed_at: new Date().toISOString()
    }
  }
}];

const item = $input.first().json;
const signal = item.validated_signal;
const risk = item.risk_plan;

const isActionableSignal = signal.signal === 'BUY' || signal.signal === 'SELL';
const hasBrokerUrl = String(item.broker_execution_webhook_url || '').trim().length > 0;
const decision = {
  action: 'NO_TRADE',
  execute: false,
  reason: 'Default safe state.',
  generated_at: new Date().toISOString()
};

if (!signal.passed) {
  decision.reason = signal.reason;
} else if (!isActionableSignal) {
  decision.reason = 'Signal is HOLD, no trade action.';
} else if (!risk.valid) {
  decision.reason = 'Risk model produced zero quantity.';
} else if (!item.dry_run && !hasBrokerUrl) {
  decision.reason = 'Live execution skipped: broker_execution_webhook_url is missing.';
} else {
  decision.action = signal.signal;
  decision.execute = true;
  decision.reason = 'Signal and risk checks passed.';
}

return [{
  json: {
    ...item,
    decision
  }
}];

const item = $input.first().json || {};
const d = item.decision || {};
const r = item.risk_plan || {};
const m = item.market_data || {};
const vs = item.validated_signal || {};

const mode = item.dry_run ? 'DRY_RUN' : 'LIVE';
const text = [
  `*Stock Market Agent* (${mode})`,
  `Run ID: ${item.run_id || 'n/a'}`,
  `Symbol: ${item.symbol || 'n/a'} (${item.exchange || 'n/a'})`,
  `Action: ${d.action || 'NO_TRADE'} | Execute: ${d.execute ?? false}`,
  `Confidence: ${vs.confidence ?? 'n/a'}`,
  `Price: ${m.price ?? 'n/a'}`,
  `Qty: ${r.quantity ?? 0} | Notional: ${r.estimated_notional ?? 'n/a'}`,
  `SL: ${r.stop_loss_price ?? 'n/a'} | TP: ${r.take_profit_price ?? 'n/a'}`,
  `Reason: ${d.reason || 'No decision reason available.'}`
].join('\n');

return [{
  json: {
    ...item,
    alert_text: text
  }
}];

const item = $input.first().json || {};
const md = item.market_data || {};
const vs = item.validated_signal || {};
const decision = item.decision || {};
const risk = item.risk_plan || {};
const ai = item.ai_analysis || {};

return [{
  json: {
    run_id: item.run_id || null,
    triggered_at: item.triggered_at || null,
    symbol: item.symbol || null,
    exchange: item.exchange || null,
    strategy_name: item.strategy_name || null,
    timeframe: item.timeframe || null,
    price: md.price ?? null,
    change_percent: md.change_percent ?? null,
    signal: vs.signal || null,
    confidence: vs.confidence ?? null,
    decision_action: decision.action || null,
    execute: decision.execute ?? false,
    dry_run: item.dry_run ?? true,
    quantity: risk.quantity ?? 0,
    stop_loss_price: risk.stop_loss_price ?? null,
    take_profit_price: risk.take_profit_price ?? null,
    estimated_notional: risk.estimated_notional ?? null,
    reason: decision.reason || 'No decision reason available.',
    analyzed_at: ai.analyzed_at || null,
    logged_at: new Date().toISOString()
  }
}];

const item = $input.first().json || {};
const decision = item.decision || {};
const validatedSignal = item.validated_signal || {};
const riskPlan = item.risk_plan || {};
const marketData = item.market_data || {};
const aiAnalysis = item.ai_analysis || {};

return [{
  json: {
    success: true,
    run_id: item.run_id || null,
    symbol: item.symbol || null,
    action: decision.action || 'NO_TRADE',
    execute: decision.execute ?? false,
    dry_run: item.dry_run ?? true,
    confidence: validatedSignal.confidence ?? null,
    quantity: riskPlan.quantity ?? 0,
    reason: decision.reason || 'No decision reason available.',
    timestamps: {
      triggered_at: item.triggered_at || null,
      market_data_collected_at: marketData.collected_at || null,
      ai_analyzed_at: aiAnalysis.analyzed_at || null,
      decision_generated_at: decision.generated_at || null
    }
  }
}];
